function Plans({items,open}:{items:any[];open:(id:string)=>void}){return <Diagnostics items={items.filter(x=>x.status?.includes('Plano')||x.status==='Reunião Agendada')} open={open}/>}
function FinancialPanel({companyId}:{companyId:string}){const empty={valor_implantacao:0,valor_mensalidade:0,desconto_pix:10,link_pix:'',link_cartao:'',link_assinatura:'',prazo_contratual:12,validade_proposta:15,status:'Links pendentes',observacoes:''};const [data,setData]=useState<any>(empty),[message,setMessage]=useState(''),[error,setError]=useState(''),[loading,setLoading]=useState(true);const load=async()=>{setLoading(true);try{const r=await fetch('/api/portal?empresa='+companyId,{cache:'no-store'}),x=await r.json();if(!r.ok)throw new Error(x.error);setData({...empty,...x.financial})}catch(e:any){setError(e?.message||'Não foi possível carregar o financeiro.')}finally{setLoading(false)}};useEffect(()=>{load()},[companyId]);const save=async()=>{setMessage('');setError('');const r=await fetch('/api/portal',{method:'PATCH',headers:{'Content-Type':'application/json'},body:JSON.stringify({empresa_id:companyId,...data})}),x=await r.json();if(r.ok){setData({...data,...x.financial});setMessage('Financeiro atualizado com sucesso.')}else setError(x.error||'Não foi possível salvar.')};const money=(v:any)=>Number(v||0).toLocaleString('pt-BR',{style:'currency',currency:'BRL'}),pix=Number(data.valor_implantacao||0)*(1-Number(data.desconto_pix||10)/100),first=Number(data.valor_implantacao||0)+Number(data.valor_mensalidade||0);if(loading)return <section className="admin-section" id="company-financial"><p>Preparando Financeiro...</p></section>;return <section className="admin-section financial-panel" id="company-financial"><span className="eyebrow">Financeiro</span><h2>Investimento e Contratação</h2><h3>Resumo Comercial</h3><div className="commercial-summary"><article><small>Valor da Implantação</small><b>{money(data.valor_implantacao)}</b></article><article><small>Assinatura mensal</small><b>{money(data.valor_mensalidade)}</b></article><article><small>PIX com {data.desconto_pix}% de desconto</small><b>{money(pix)}</b></article><article><small>Primeiro investimento</small><b>{money(first)}</b></article><article><small>Prazo contratual</small><b>{data.prazo_contratual} meses</b></article><article><small>Status da proposta</small><b>{data.status}</b></article></div><div className="financial-form"><label>Valor da Implantação<input type="number" min="0" step="0.01" value={data.valor_implantacao} readOnly/></label><label>Mensalidade Escala Growth<input type="number" min="0" step="0.01" value={data.valor_mensalidade} onChange={e=>setData({...data,valor_mensalidade:Number(e.target.value)})}/></label><label>Desconto PIX (%)<input type="number" min="0" max="100" value={data.desconto_pix} readOnly/></label><label>Prazo contratual (meses)<input type="number" min="1" value={data.prazo_contratual} readOnly/></label><label>Validade da proposta (dias)<input type="number" value={data.validade_proposta} readOnly/></label><label className="wide">Link PIX<input value={data.link_pix||''} onChange={e=>setData({...data,link_pix:e.target.value})} placeholder="https://..."/></label><label className="wide">Link Cartão<input value={data.link_cartao||''} onChange={e=>setData({...data,link_cartao:e.target.value})} placeholder="https://..."/></label><label className="wide">Link Assinatura<input value={data.link_assinatura||''} onChange={e=>setData({...data,link_assinatura:e.target.value})} placeholder="https://..."/></label><label>Status Financeiro<select value={data.status} onChange={e=>setData({...data,status:e.target.value})}>{['Links pendentes','Proposta pronta','Aceite realizado','Pagamento aguardando confirmação','Pagamento confirmado','Kickoff liberado'].map(x=><option key={x}>{x}</option>)}</select></label><label className="wide">Observações<textarea rows={4} value={data.observacoes||''} onChange={e=>setData({...data,observacoes:e.target.value})}/></label></div><div className="financial-checks"><span>PIX {data.link_pix?'✓ Link cadastrado':'— Pendente'}</span><span>Cartão {data.link_cartao?'✓ Link cadastrado':'— Pendente'}</span><span>Assinatura {data.link_assinatura?'✓ Link cadastrado':'— Pendente'}</span></div><button className="btn btn-primary" onClick={save}>Salvar Financeiro</button>{message&&<p className="success">{message}</p>}{error&&<p className="error">{error}</p>}</section>}
function Agenda({items,open}:{items:any[];open:(id:string)=>void}){const [meetings,setMeetings]=useState<any[]>([]),[filter,setFilter]=useState('próximas'),[editing,setEditing]=useState<any>(null);const empty={empresa_id:'',diagnostico_id:'',responsavel_nome:'',data:'',hora:'',duracao:60,consultor:'Teófilo Oliveira Fagundes',status:'Agendada',observacoes:''};const load=()=>fetch('/api/central?resource=meetings').then(r=>r.json()).then(setMeetings);useEffect(()=>{load()},[]);const save=async()=>{const method=editing.id?'PATCH':'POST';await fetch('/api/central?resource=meetings',{method,headers:{'Content-Type':'application/json'},body:JSON.stringify(editing)});setEditing(null);load()};const remove=async(id:string)=>{if(confirm('Excluir esta reunião?')){await fetch('/api/central?resource=meetings&id='+id,{method:'DELETE'});load()}};const visible=meetings.filter(m=>filter==='realizadas'?m.status==='Realizada':filter==='canceladas'?m.status==='Cancelada':true);return <><div className="module-toolbar"><div>{['hoje','esta semana','próximas','realizadas','canceladas'].map(x=><button className={filter===x?'active':''} onClick={()=>setFilter(x)} key={x}>{x}</button>)}</div><button className="btn btn-primary" onClick={()=>setEditing(empty)}>Nova Reunião</button></div>{editing&&<div className="meeting-form admin-section"><h2>{editing.id?'Editar':'Nova'} Reunião</h2><div>{[['empresa_id','Empresa'],['responsavel_nome','Responsável'],['data','Data'],['hora','Hora'],['duracao','Duração'],['consultor','Consultor']].map(([k,l])=><label key={k}>{l}{k==='empresa_id'?<select value={editing[k]} onChange={e=>{const d=items.find(x=>x.empresas?.id===e.target.value);setEditing({...editing,[k]:e.target.value,diagnostico_id:d?.id,responsavel_nome:d?.responsaveis?.nome||''})}}><option value="">Selecione</option>{items.map(x=><option value={x.empresas?.id} key={x.id}>{x.empresas?.nome}</option>)}</select>:<input required type={k==='data'?'date':k==='hora'?'time':k==='duracao'?'number':'text'} value={editing[k]} onChange={e=>setEditing({...editing,[k]:e.target.value})}/>}</label>)}<label>Status<select value={editing.status} onChange={e=>setEditing({...editing,status:e.target.value})}>{['Agendada','Confirmada','Realizada','Cancelada','Reagendada','Não compareceu'].map(x=><option key={x}>{x}</option>)}</select></label><label>Observações<textarea value={editing.observacoes||''} onChange={e=>setEditing({...editing,observacoes:e.target.value})}/></label></div><button className="btn btn-primary" onClick={save}>Salvar</button><button className="btn btn-secondary" onClick={()=>setEditing(null)}>Cancelar</button></div>}<div className="agenda-list">{visible.map(m=><article key={m.id}><div><small>Reunião estratégica</small><h3>{items.find(x=>x.empresas?.id===m.empresa_id)?.empresas?.nome||'Empresa'}</h3><p>{m.responsavel_nome} · {m.consultor}</p></div><span>{date(m.data)} · {m.hora?.slice(0,5)}<b>{m.duracao} minutos · {m.status}</b></span><button onClick={()=>setEditing(m)}>Editar</button><button onClick={()=>fetch('/api/central?resource=meetings',{method:'PATCH',headers:{'Content-Type':'application/json'},body:JSON.stringify({...m,status:'Realizada'})}).then(load)}>Realizada</button><button onClick={()=>remove(m.id)}>Excluir</button>{m.diagnostico_id&&<button onClick={()=>open(m.diagnostico_id)}>Abrir Diagnóstico</button>}</article>)}</div></>}
function Implantations({items}:{items:any[]}){return <div className="company-grid">{items.filter(x=>x.status?.includes('Implantação')).map(x=><article key={x.id}><span className="status-pill">Em implantação</span><h3>{x.empresas?.nome}</h3><p>Projeto: Evolução Escala Growth</p><div className="progress-line"><i style={{width:'25%'}}/></div><small>Próxima ação: validar cronograma executivo</small></article>)}</div>}
function Evolution({items}:{items:any[]}){return <div className="company-grid">{Object.values(items.reduce((a:any,x:any)=>{const n=x.empresas?.nome;(a[n]??={name:n,values:[]}).values.push(x);return a},{})).map((g:any)=><article key={g.name}><h3>{g.name}</h3><div className="evolution-numbers"><b>{g.values.at(-1)?.pontuacao_geral}<small>IEG inicial</small></b><span>→</span><b>{g.values[0]?.pontuacao_geral}<small>IEG atual</small></b><b>85<small>Meta</small></b></div><p>{g.values.length} diagnóstico(s) no histórico</p><div className="trend-line">{g.values.reverse().map((x:any)=><i style={{height:x.pontuacao_geral+'%'}} key={x.id}/>)}</div></article>)}</div>}
function UserAccessSettings(){const [users,setUsers]=useState<any[]>([]),[companies,setCompanies]=useState<any[]>([]),[form,setForm]=useState<any>({email:'',perfil:'cliente',empresa_id:'',ativo:true}),[message,setMessage]=useState(''),[error,setError]=useState(''),[busy,setBusy]=useState(false);const load=()=>fetch('/api/users',{cache:'no-store'}).then(async r=>{const x=await r.json();if(!r.ok)throw new Error(x.error);setUsers(x.users||[]);setCompanies(x.companies||[])}).catch(e=>setError(e.message));useEffect(()=>{load()},[]);const save=async()=>{setBusy(true);setError('');setMessage('');try{const r=await fetch('/api/users',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(form)}),x=await r.json();if(!r.ok)throw new Error(x.error||'N?o foi poss?vel salvar o usu?rio.');setMessage('Tipo de usu?rio salvo com sucesso.');setForm({email:'',perfil:'cliente',empresa_id:'',ativo:true});load()}catch(e:any){setError(e.message)}finally{setBusy(false)}};return <div className="user-access-settings"><h3>Tipos de usu?rio</h3><p className="muted">Nesta vers?o existem apenas Master e Cliente. Novos perfis ser?o criados somente quando houver necessidade operacional real.</p><div className="form-grid"><label>E-mail<input type="email" value={form.email} onChange={e=>setForm({...form,email:e.target.value})}/></label><label>Tipo de usu?rio<select value={form.perfil} onChange={e=>setForm({...form,perfil:e.target.value,empresa_id:e.target.value==='master'?'':form.empresa_id})}><option value="master">Master</option><option value="cliente">Cliente</option></select></label>{form.perfil==='cliente'&&<label>Empresa<select value={form.empresa_id} onChange={e=>setForm({...form,empresa_id:e.target.value})}><option value="">Selecione</option>{companies.map(x=><option key={x.id} value={x.id}>{x.nome}</option>)}</select></label>}</div><button className="btn btn-primary" disabled={busy} onClick={save}>{busy?'Salvando...':'Salvar tipo de usu?rio'}</button>{message&&<p className="success">{message}</p>}{error&&<p className="error" role="alert">{error}</p>}<div className="table-wrap"><table><thead><tr><th>E-mail</th><th>Tipo</th><th>Empresa</th><th>Status</th></tr></thead><tbody>{users.map(u=><tr key={u.id}><td>{u.email}</td><td>{u.perfil==='master'?'Master':'Cliente'}</td><td>{companies.find(c=>c.id===u.empresa_id)?.nome||'?'}</td><td>{u.ativo===false?'Inativo':'Ativo'}</td></tr>)}</tbody></table></div></div>}

function Settings(){const fallback='/logo-escala-vendas.png';const initial={nome_empresa:'Escala Vendas',consultor:'Teófilo Oliveira Fagundes',cargo:'Consultor',cra:'6000811',agenda_url:'https://cal.com/teofilo-fagundes-8o0j6j/60min'};const [data,setData]=useState<any>(initial),[preview,setPreview]=useState(fallback),[file,setFile]=useState<File|null>(null),[message,setMessage]=useState(''),[error,setError]=useState(''),[busy,setBusy]=useState(false);const readResponse=async(r:Response)=>{const text=await r.text();if(!text)return{error:`O servidor respondeu sem conteúdo (HTTP ${r.status}).`};try{return JSON.parse(text)}catch{return{error:text.slice(0,180)||`Resposta inválida do servidor (HTTP ${r.status}).`}}};useEffect(()=>{let active=true;fetch('/api/central?resource=config',{cache:'no-store'}).then(async r=>{const x=await readResponse(r);if(!r.ok)throw new Error(x.error||'Não foi possível carregar as configurações.');if(active&&x[0]){setData({...initial,...x[0]});setPreview(x[0].logo_url||fallback)}}).catch(e=>active&&setError(e.message));return()=>{active=false}},[]);useEffect(()=>()=>{if(preview.startsWith('blob:'))URL.revokeObjectURL(preview)},[preview]);const clear=()=>{setMessage('');setError('')};const choose=(f?:File)=>{if(!f)return;clear();if(f.size>3*1024*1024||!['image/png','image/jpeg','image/webp'].includes(f.type)){setError('Use PNG, JPG ou WEBP com até 3 MB.');return}setFile(f);setPreview(URL.createObjectURL(f))};const upload=async()=>{if(!file)return;clear();setBusy(true);try{const form=new FormData();form.append('logo',file);const r=await fetch('/api/central?resource=logo',{method:'POST',body:form});const x=await readResponse(r);if(!r.ok)throw new Error(x.error||'Não foi possível salvar a logo.');setPreview(x.logo_url);setData((current:any)=>({...current,logo_url:x.logo_url.split('?')[0]}));setFile(null);brandingPromise=null;window.dispatchEvent(new CustomEvent('branding-updated',{detail:x.logo_url}));setMessage('Logo atualizada e salva com sucesso.')}catch(e:any){setError(e.message)}finally{setBusy(false)}};const save=async()=>{clear();setBusy(true);try{const r=await fetch('/api/central?resource=config',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(data)});const x=await readResponse(r);if(!r.ok)throw new Error(x.error||'Não foi possível salvar as configurações.');brandingPromise=null;setMessage('Configurações salvas com sucesso.')}catch(e:any){setError(e.message)}finally{setBusy(false)}};const fields=[['nome_empresa','Nome da empresa'],['telefone','Telefone'],['whatsapp','WhatsApp'],['email','E-mail'],['website','Website'],['instagram','Instagram'],['linkedin','LinkedIn'],['consultor','Nome do consultor'],['cargo','Cargo'],['cra','CRA'],['agenda_url','Link da agenda'],['assinatura_url','Assinatura digital']];return <section className="admin-section settings-premium"><div className="logo-setting"><img key={preview} src={preview} alt="Escala Vendas" onError={e=>{const image=e.currentTarget;if(new URL(image.src).pathname===fallback){image.onerror=null;return}image.src=fallback}}/><div><input id="logo-upload" hidden type="file" accept=".png,.jpg,.jpeg,.webp" onChange={e=>choose(e.target.files?.[0])}/><label className="btn btn-secondary" htmlFor="logo-upload">Alterar logo</label><button className="btn btn-primary" disabled={!file||busy} onClick={upload}>{busy?'Salvando...':'Salvar logo'}</button><small>PNG, JPG ou WEBP ? máximo 3 MB</small></div></div><div>{fields.map(([k,l])=><label key={k}>{l}<input value={data[k]||''} onChange={e=>setData({...data,[k]:e.target.value})}/></label>)}</div><button className="btn btn-primary" disabled={busy} onClick={save}>{busy?'Salvando...':'Salvar configurações'}</button>{message&&<p className="success">{message}</p>}{error&&<p className="error" role="alert">{error}</p>}<UserAccessSettings/></section>}
const date=(d:string)=>d?new Date(d+'T12:00:00').toLocaleDateString('pt-BR'):'—';

